import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import DatePicker from 'react-datepicker';
import { bookingApi } from '../../api/bookingApi';
import ConflictWarning from './ConflictWarning';
import { ROOMS } from '../../utils/constants';
import 'react-datepicker/dist/react-datepicker.css';

const BookingForm = ({ onSuccess, onCancel }) => {
  const navigate = useNavigate();

  const dayStart = useMemo(() => {
    const d = new Date();
    d.setHours(0, 0, 0, 0);
    return d;
  }, []);

  const dayEnd = useMemo(() => {
    const d = new Date();
    d.setHours(23, 59, 0, 0);
    return d;
  }, []);

  const [formData, setFormData] = useState({
    resourceId: '',
    resourceName: '',
    bookingDate: null,
    startTime: null,
    endTime: null,
    purpose: '',
    expectedAttendees: '',
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [conflict, setConflict] = useState({ hasConflict: false, resourceName: '' });

  const combineDateAndTime = (date, time) => {
    if (!date || !time) return null;
    const combined = new Date(date);
    combined.setHours(time.getHours(), time.getMinutes(), 0, 0);
    return combined;
  };

  const startDateTime = useMemo(
    () => combineDateAndTime(formData.bookingDate, formData.startTime),
    [formData.bookingDate, formData.startTime]
  );

  const endDateTime = useMemo(
    () => combineDateAndTime(formData.bookingDate, formData.endTime),
    [formData.bookingDate, formData.endTime]
  );

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleDateChange = (date, field) => {
    setFormData({ ...formData, [field]: date });
  };

  const handleResourceChange = (e) => {
    const selectedId = parseInt(e.target.value, 10);
    const selectedRoom = ROOMS.find((room) => room.id === selectedId);

    if (!selectedRoom) {
      setFormData({ ...formData, resourceId: '', resourceName: '' });
      return;
    }

    setFormData({
      ...formData,
      resourceId: selectedRoom.id,
      resourceName: selectedRoom.name,
    });
  };

  const checkConflict = async () => {
    if (!formData.resourceId || !startDateTime || !endDateTime) return;
    
    try {
      const result = await bookingApi.checkConflict(
        formData.resourceId,
        startDateTime.toISOString(),
        endDateTime.toISOString()
      );
      setConflict({
        hasConflict: result.hasConflict,
        resourceName: formData.resourceName
      });
    } catch (err) {
      console.error('Error checking conflict:', err);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      if (!startDateTime || !endDateTime) {
        throw new Error('Please select booking date and times');
      }

      if (endDateTime <= startDateTime) {
        throw new Error('End time must be after start time');
      }

      const bookingData = {
        resourceId: parseInt(formData.resourceId),
        resourceName: formData.resourceName,
        startTime: startDateTime.toISOString(),
        endTime: endDateTime.toISOString(),
        purpose: formData.purpose,
        expectedAttendees: parseInt(formData.expectedAttendees) || null,
      };

      await bookingApi.createBooking(bookingData);
      if (typeof onSuccess === 'function') {
        onSuccess();
      } else {
        navigate('/bookings/success');
      }
    } catch (err) {
      setError(err.message || 'Failed to create booking');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const shouldCheck =
      Boolean(formData.resourceId) && Boolean(startDateTime) && Boolean(endDateTime);

    if (!shouldCheck) {
      setConflict({ hasConflict: false, resourceName: '' });
      return;
    }

    const timer = setTimeout(() => {
      checkConflict();
    }, 400);

    return () => clearTimeout(timer);
  }, [formData.resourceId, startDateTime, endDateTime]);

  return (
    <div className="booking-form-page">
      <div className="booking-form-page-header">
        <h1>Create New Booking</h1>
        <p>Reserve campus resources and schedule your next session.</p>
      </div>

      <form className="booking-form booking-form-v2" onSubmit={handleSubmit}>
        <div className="booking-form-section-heading">
          <span className="booking-form-section-accent" aria-hidden="true" />
          <h2>Reservation Details</h2>
        </div>

        {error && <div className="error-message">{error}</div>}

        <ConflictWarning
          hasConflict={conflict.hasConflict}
          resourceName={conflict.resourceName}
          startTime={startDateTime || new Date()}
          endTime={endDateTime || new Date()}
        />

        <div className="form-group">
          <label>Select Resource</label>
          <select
            name="resourceName"
            value={formData.resourceId}
            onChange={handleResourceChange}
            required
          >
            <option value="">Select a room</option>
            {ROOMS.map((room) => (
              <option key={room.id} value={room.id}>
                {room.name} ({room.type})
              </option>
            ))}
          </select>
        </div>

        <div className="form-row">
          <div className="form-group">
            <label>Booking Date</label>
            <DatePicker
              selected={formData.bookingDate}
              onChange={(date) => handleDateChange(date, 'bookingDate')}
              dateFormat="MM/dd/yyyy"
              minDate={new Date()}
              placeholderText="mm/dd/yyyy"
              required
            />
          </div>

          <div className="form-group">
            <label>Expected Attendees</label>
            <input
              type="number"
              name="expectedAttendees"
              value={formData.expectedAttendees}
              onChange={handleChange}
              placeholder="0"
              min="0"
            />
          </div>
        </div>

        <div className="form-row">
          <div className="form-group">
            <label>Start Time</label>
            <DatePicker
              selected={formData.startTime}
              onChange={(date) => handleDateChange(date, 'startTime')}
              showTimeSelect
              showTimeSelectOnly
              timeIntervals={15}
              timeCaption="Time"
              dateFormat="h:mm aa"
              minTime={dayStart}
              maxTime={dayEnd}
              placeholderText="--:--"
              required
            />
          </div>

          <div className="form-group">
            <label>End Time</label>
            <DatePicker
              selected={formData.endTime}
              onChange={(date) => handleDateChange(date, 'endTime')}
              showTimeSelect
              showTimeSelectOnly
              timeIntervals={15}
              timeCaption="Time"
              dateFormat="h:mm aa"
              minTime={dayStart}
              maxTime={dayEnd}
              placeholderText="--:--"
              required
            />
          </div>
        </div>

        <div className="form-group">
          <label>Purpose Of Booking</label>
          <textarea
            name="purpose"
            value={formData.purpose}
            onChange={handleChange}
            required
            rows="3"
            placeholder="Briefly describe the event or meeting agenda..."
          />
        </div>

        <div className="form-actions booking-form-actions">
          <button
            type="button"
            className="booking-form-cancel"
            onClick={() => {
              if (typeof onCancel === 'function') {
                onCancel();
              } else {
                navigate('/bookings');
              }
            }}
          >
            Cancel
          </button>
          <button type="submit" className="btn-submit booking-form-submit" disabled={loading}>
            {loading ? 'Creating...' : 'Create Booking'}
          </button>
        </div>
      </form>
    </div>
  );
};

export default BookingForm;
